import{supabase,isSupabaseConfigured,getSupabase}from './supabase.js';import{applyUserTheme}from './utils.js';async function getClient(){if(!isSupabaseConfigured)return null;if(supabase)return supabase;return await getSupabase();}export async function signUp(email,password,username){if(!isSupabaseConfigured){throw new Error("Supabase no está configurado. Revisa js/config.js.");}const client=await getClient();const siteUrl='https://cineverse-7u5.pages.dev';const{data,error}=await client.auth.signUp({email,password,options:{emailRedirectTo:`${siteUrl}/login.html`,data:{username:username,display_name:username}}});if(error)throw error;return data;}export async function signIn(email,password){if(!isSupabaseConfigured){throw new Error("Supabase no está configurado. Revisa js/config.js.");}const client=await getClient();const{data,error}=await client.auth.signInWithPassword({email,password});if(error)throw error;return data;}export async function signInWithGoogle(){if(!isSupabaseConfigured){throw new Error("Supabase no está configurado. Revisa js/config.js.");}const client=await getClient();const{data,error}=await client.auth.signInWithOAuth({provider:'google',options:{redirectTo:window.location.origin+'/index.html'}});if(error)throw error;return data;}export async function signOut(){if(!isSupabaseConfigured)return;localStorage.removeItem('cineverse_profile');localStorage.removeItem('cineverse_theme_color');applyUserTheme('red');const client=await getClient();if(!client)return;const{error}=await client.auth.signOut();if(error)throw error;}export async function getCurrentUser(){if(!isSupabaseConfigured)return null;try{const client=await getClient();if(!client)return null;const{data:{user},error:userError}=await client.auth.getUser();if(userError||!user)return null;let{data:profile,error:profileError}=await client .from('profiles').select('*').eq('id',user.id).maybeSingle();if(profileError){console.error("Error al obtener perfil extendido:",profileError);}if(!profile){const email=user.email||'';const username=email.split('@')[0]||`user_${user.id.substring(0,8)}`;const{data:newProfile,error:insertError}=await client .from('profiles').insert({id:user.id,username:username,display_name:username,bio:''}).select().maybeSingle();if(!insertError&&newProfile){profile=newProfile;}else{console.error("Error al auto-crear perfil en getCurrentUser:",insertError);const{data:fallbackProfile}=await client .from('profiles').select('*').eq('id',user.id).maybeSingle();if(fallbackProfile){profile=fallbackProfile;}}}if(profile&&profile.is_premium&&profile.premium_until){const now=new Date();const expiry=new Date(profile.premium_until);if(now>expiry){try{await client .from('profiles').update({is_premium:false}).eq('id',user.id);profile.is_premium=false;console.log("Premium ha expirado de forma automática.");}catch(e){console.error("Error al expirar premium en base de datos:",e);}}}if(profile){localStorage.setItem('cineverse_profile',JSON.stringify(profile));if(profile.is_premium){const themeToApply=profile.theme_color||'red';localStorage.setItem('cineverse_theme_color',themeToApply);applyUserTheme(themeToApply);}else{localStorage.setItem('cineverse_theme_color','red');applyUserTheme('red');}}else{localStorage.removeItem('cineverse_profile');localStorage.setItem('cineverse_theme_color','red');applyUserTheme('red');}return{...user,profile};}catch(err){console.error("Error en getCurrentUser:",err);return null;}}export function onAuthStateChange(cb){if(!isSupabaseConfigured){cb('INITIAL_SESSION_VAL',null,null);return()=>{};}let unsubscribeFn=null;let isUnsubscribed=false;getClient().then(client=>{if(isUnsubscribed)return;if(!client){cb('INITIAL_SESSION_VAL',null,null);return;}const{data:{subscription}}=client.auth.onAuthStateChange(async(event,session)=>{if(session?.user){try{let{data:profile,error:profileError}=await client .from('profiles').select('*').eq('id',session.user.id).maybeSingle();if(!profile){const email=session.user.email||'';const username=email.split('@')[0]||`user_${session.user.id.substring(0,8)}`;const{data:newProfile}=await client .from('profiles').insert({id:session.user.id,username:username,display_name:username,bio:''}).select().maybeSingle();if(newProfile)profile=newProfile;}if(profile&&profile.is_premium&&profile.premium_until){const now=new Date();const expiry=new Date(profile.premium_until);if(now>expiry){try{await client .from('profiles').update({is_premium:false}).eq('id',session.user.id);profile.is_premium=false;}catch(e){console.error("Error al expirar premium en onAuthStateChange:",e);}}}if(profile){localStorage.setItem('cineverse_profile',JSON.stringify(profile));if(profile.is_premium){const themeToApply=profile.theme_color||'red';localStorage.setItem('cineverse_theme_color',themeToApply);applyUserTheme(themeToApply);}else{localStorage.setItem('cineverse_theme_color','red');applyUserTheme('red');}}else{localStorage.removeItem('cineverse_profile');localStorage.setItem('cineverse_theme_color','red');applyUserTheme('red');}cb(event,session,profile);}catch(e){console.error("Error fetching/creating profile in onAuthStateChange:",e);cb(event,session,null);}}else{localStorage.removeItem('cineverse_profile');localStorage.setItem('cineverse_theme_color','red');applyUserTheme('red');cb(event,null,null);}});unsubscribeFn=()=>subscription.unsubscribe();});return()=>{isUnsubscribed=true;if(unsubscribeFn)unsubscribeFn();};}export async function resetPassword(email){if(!isSupabaseConfigured){throw new Error("Supabase no está configurado. Revisa js/config.js.");}const client=await getClient();const{data,error}=await client.auth.resetPasswordForEmail(email,{redirectTo:window.location.origin+'/login.html?reset=true'});if(error)throw error;return data;}export async function updateProfile(data){if(!isSupabaseConfigured){throw new Error("Supabase no está configurado. Revisa js/config.js.");}const client=await getClient();const{data:{user}}=await client.auth.getUser();if(!user)throw new Error("No hay usuario autenticado.");const{error}=await client .from('profiles').update({...data,updated_at:new Date().toISOString()}).eq('id',user.id);if(error)throw error;try{const currentCached=JSON.parse(localStorage.getItem('cineverse_profile')||'{}');const updatedProfile={...currentCached,...data};localStorage.setItem('cineverse_profile',JSON.stringify(updatedProfile));}catch(e){console.error("Error al actualizar cineverse_profile en localStorage:",e);}}export async function uploadAvatar(file){if(!isSupabaseConfigured){throw new Error("Supabase no está configurado. Revisa js/config.js.");}const client=await getClient();const{data:{user}}=await client.auth.getUser();if(!user)throw new Error("No hay usuario autenticado.");const fileExt=file.name.split('.').pop();const filePath=`${user.id}/${Math.random().toString(36).substring(2)}.${fileExt}`;const{error:uploadError}=await client.storage .from('avatars').upload(filePath,file,{upsert:true});if(uploadError)throw uploadError;const{data:{publicUrl}}=client.storage .from('avatars').getPublicUrl(filePath);return publicUrl;}export async function addXP(amount){if(!isSupabaseConfigured)return null;try{const client=await getClient();if(!client)return null;const{data:{user},error:userError}=await client.auth.getUser();if(userError||!user)return null;const{data:profile,error:profileError}=await client .from('profiles').select('xp,level').eq('id',user.id).maybeSingle();if(profileError||!profile)return null;let newXP=(profile.xp||0)+amount;let newLevel=profile.level||1;let xpNeeded=newLevel*100;let leveledUp=false;while(newXP>=xpNeeded){newXP-=xpNeeded;newLevel+=1;xpNeeded=newLevel*100;leveledUp=true;}const{error:updateError}=await client .from('profiles').update({xp:newXP,level:newLevel,updated_at:new Date().toISOString()}).eq('id',user.id);if(updateError)throw updateError;try{const cached=JSON.parse(localStorage.getItem('cineverse_profile')||'{}');cached.xp=newXP;cached.level=newLevel;localStorage.setItem('cineverse_profile',JSON.stringify(cached));}catch(e){}return{leveledUp,newLevel,newXP,xpAdded:amount};}catch(err){console.error("Error en addXP:",err);return null;}}if(typeof window!=='undefined'){setTimeout(()=>{let wasPremium=false;let hadProfile=false;try{const cached=localStorage.getItem('cineverse_profile');if(cached){hadProfile=true;const profile=JSON.parse(cached);wasPremium=!!profile.is_premium;}}catch(e){console.error('[Auth System]Error al leer caché en segundo plano:',e);}getCurrentUser().then(userObj=>{if(userObj&&userObj.profile){const isPremiumNow=!!userObj.profile.is_premium;if(wasPremium!==isPremiumNow){console.log(`[Auth System]Estado Premium cambió de ${wasPremium}a ${isPremiumNow}. Recargando...`);window.location.reload();}}else{if(hadProfile){console.warn('[Auth System]Sesión expirada o cerrada. Limpiando caché...');localStorage.removeItem('cineverse_profile');localStorage.removeItem('cineverse_theme_color');applyUserTheme('red');window.location.reload();}}}).catch(err=>{console.error('[Auth System]Error al validar sesión en segundo plano:',err);});},2000);}